import{c as t,Q as o,j as a,m as s}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"Tiered autonomy","description":"The four-tier state machine that controls what the agent can do without asking.","frontmatter":{"title":"Tiered autonomy","description":"The four-tier state machine that controls what the agent can do without asking."},"headers":[],"relativePath":"policy/tiered-autonomy.md","filePath":"policy/tiered-autonomy.md","lastUpdated":1778983454000}'),i={name:"policy/tiered-autonomy.md"};function n(r,e,l,d,c,h){return o(),a("div",null,[...e[0]||(e[0]=[s(`<h1 id="tiered-autonomy" tabindex="-1">Tiered autonomy <a class="header-anchor" href="#tiered-autonomy" aria-label="Permalink to &quot;Tiered autonomy&quot;">​</a></h1><p>Tiered autonomy is the <strong>substrate</strong> every agentic surface shares. It controls <strong>how much the agent can do without asking you each time</strong> — from &quot;ask me every action&quot; to &quot;act within my encrypted bounds and notify on breach.&quot;</p><p>You set your tier with <code>muhaven_set_policy(tier, params)</code> on HavenBot, or <code>muhaven.policy.set_tier</code> on MCP / OpenClaw. The tier choice is signed by your passkey. See the <a href="/reference/tool-catalog">Tool catalog</a> for the cross-surface name mapping.</p><h2 id="the-four-tiers" tabindex="-1">The four tiers <a class="header-anchor" href="#the-four-tiers" aria-label="Permalink to &quot;The four tiers&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                                                                  │</span></span>
<span class="line"><span>│   Advisory  ──►  Confirm-per-action  ──►  Policy-bound  ──►      │</span></span>
<span class="line"><span>│       ▲                  ▲                     ▲            │    │</span></span>
<span class="line"><span>│       └──── /pause ──────┴───── /pause ────────┴── /pause ──┘    │</span></span>
<span class="line"><span>│                                                            │     │</span></span>
<span class="line"><span>│                                                            ▼     │</span></span>
<span class="line"><span>│                                                        Paused    │</span></span>
<span class="line"><span>│                                                                  │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────────────────┘</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Tier</th><th>What happens on every action</th></tr></thead><tbody><tr><td><strong>Advisory</strong></td><td>LLM proposes; you sign <strong>each</strong> action with your passkey.</td></tr><tr><td><strong>Confirm-per-action</strong></td><td>LLM proposes; <strong>session key</strong> signs without re-prompting passkey, within the 1-hour TTL. Each action still opens ConfirmModal.</td></tr><tr><td><strong>Policy-bound</strong></td><td>LLM proposes; if within your encrypted thresholds (max drawdown, daily spend, etc.), <strong>cron policy engine</strong> signs without confirmation. Breaches auto-pause and notify.</td></tr><tr><td><strong>Paused</strong></td><td>All <code>propose</code> tools return 423 PAUSED. Read tools still work. Only <code>pause</code> is idempotent (always allowed).</td></tr></tbody></table><h2 id="default-tier-ladder" tabindex="-1">Default tier ladder <a class="header-anchor" href="#default-tier-ladder" aria-label="Permalink to &quot;Default tier ladder&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Investor stage</th><th>Default tier</th></tr></thead><tbody><tr><td>Onboarding (&lt;30 days, &lt;$5K deposits)</td><td>Advisory</td></tr><tr><td>Returning user (≥5 confirmed actions, no breach in 30d)</td><td>Confirm-per-action</td></tr><tr><td>Power user / accredited</td><td>Policy-bound (opt-in)</td></tr><tr><td>After a breach</td><td>Paused (auto-flipped)</td></tr></tbody></table><p>The progression mirrors <strong>SEC IM-2017-02</strong> + <strong>FINRA Reg BI Care Obligation</strong> framing — small / new investors get the most friction; experienced / accredited investors get the least.</p><h2 id="advisory-—-the-default" tabindex="-1">Advisory — the default <a class="header-anchor" href="#advisory-—-the-default" aria-label="Permalink to &quot;Advisory — the default&quot;">​</a></h2><p>Every action prompts your passkey. ConfirmModal opens, you confirm with WebAuthn (Touch ID / Windows Hello / hardware key), the UserOp signs.</p><p><strong>When to use:</strong> during onboarding, after a long break, when you&#39;re not sure what the agent will do.</p><p><strong>Trade-off:</strong> highest friction, highest assurance. Every action is single-signed by you.</p><h2 id="confirm-per-action-—-the-daily-driver-tier" tabindex="-1">Confirm-per-action — the daily-driver tier <a class="header-anchor" href="#confirm-per-action-—-the-daily-driver-tier" aria-label="Permalink to &quot;Confirm-per-action — the daily-driver tier&quot;">​</a></h2><p>Your MuHaven wallet installs a <strong>session key</strong> at sign-in. The session key has narrow scope:</p><ul><li>Target: only MuHaven contracts.</li><li>Selector allowlist: only MuHaven SDK functions.</li><li>Value cap per call.</li><li>Total cap per epoch (your daily-spend ceiling, if set).</li><li><code>validUntil</code>: 1 hour from install.</li></ul><p>For the next hour, the session key signs without re-prompting your passkey. ConfirmModal still opens per-action (cleartext preview), but the <strong>signing</strong> is automatic via the session key.</p><p>After 1 hour, the session key expires. The next action prompts your passkey to install a fresh one.</p><p><strong>When to use:</strong> active trading sessions (1-2 hours of HavenBot conversation), repeated claims, working through a batch of actions.</p><p><strong>Trade-off:</strong> medium friction, medium assurance. You confirm what; you don&#39;t re-prove who.</p><h2 id="policy-bound-—-the-automation-tier" tabindex="-1">Policy-bound — the automation tier <a class="header-anchor" href="#policy-bound-—-the-automation-tier" aria-label="Permalink to &quot;Policy-bound — the automation tier&quot;">​</a></h2><p>Your MuHaven wallet installs the session key as in Confirm-per-action, <strong>and</strong> you set encrypted thresholds on what counts as &quot;within bounds&quot;:</p><ul><li><strong>Max drawdown per position</strong> — e.g., 10% of cost basis.</li><li><strong>Max daily spend</strong> — e.g., $500 per 24-hour window.</li><li><strong>Min yield to accept</strong> — e.g., 1% APR floor.</li><li><strong>Drift tolerance</strong> — e.g., trigger a rebalance when allocation drifts &gt;5% from target.</li></ul><p>A backend <strong>cron policy engine</strong> ticks every 60 seconds. For each pending action, it checks the proposed amount against your encrypted thresholds. If the check passes, the session key signs without prompting you. If it fails (a breach), the engine auto-pauses you to Advisory and notifies you.</p><details class="details custom-block"><summary>Under the hood — for the curious</summary><ul><li>Thresholds live encrypted on-chain (<code>RiskParams.sol</code>, <code>euint64</code> slots).</li><li>The check uses a <strong>branchless <code>FHE.select</code></strong> so the gas cost is identical whether the threshold passes or fails — no decrypt-event timing leakage.</li><li>On breach: async-decrypt on Fhenix Threshold Network + on-chain <code>settleBreachDecrypt</code> on Arbitrum.</li><li>A <code>RiskBreach</code> event fires on-chain; the engine then calls <code>PauseAgentUseCase</code> to uninstall the session-key validator.</li></ul></details><p><strong>When to use:</strong> auto-claim cron jobs, rebalancing on drift, set-and-forget yield management.</p><p><strong>Trade-off:</strong> lowest friction, highest pre-configured assurance. You define the bounds; the agent acts within them.</p><h3 id="what-a-breach-does" tabindex="-1">What a breach does <a class="header-anchor" href="#what-a-breach-does" aria-label="Permalink to &quot;What a breach does&quot;">​</a></h3><p>If any of your thresholds is exceeded (max drawdown / daily spend / min yield / drift tolerance), the cron engine:</p><ol><li>Async-decrypts the breach event.</li><li>Emits an on-chain <code>RiskBreach</code> event.</li><li>Calls the same pause cascade as <code>/pause</code> — uninstalls your session-key validator across every surface.</li><li>Notifies you (Telegram if linked, dashboard banner on next visit).</li><li>Writes <code>breach_detected</code> + <code>pause_triggered</code> rows to your audit log.</li></ol><p>Resume requires a manual passkey ceremony — there is no &quot;auto-resume after N minutes&quot; path. The investor must affirmatively re-engage.</p><div class="warning custom-block"><p class="custom-block-title">Policy-bound is opt-in</p><p>Policy-bound never engages by default, even after the ≥5-confirmed-actions ladder graduation. You have to explicitly request it via <code>muhaven_set_policy(tier: &#39;policy_bound&#39;, params: {...})</code> and sign with your passkey.</p></div><h2 id="paused-—-the-kill-switch-state" tabindex="-1">Paused — the kill-switch state <a class="header-anchor" href="#paused-—-the-kill-switch-state" aria-label="Permalink to &quot;Paused — the kill-switch state&quot;">​</a></h2><p>Anyone (in any surface) can call <code>pause</code> at any time:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; Pause my agent.</span></span></code></pre></div><p>The on-chain effect: <code>uninstallPlugin(sessionKeyValidator)</code> — a single tx that removes the session key from your MuHaven wallet&#39;s permission system. ≤1 Arb block.</p><p>Once paused:</p><ul><li>All <code>propose</code> tools return <code>423 PAUSED</code>.</li><li>Read tools still work.</li><li><code>pause</code> itself is idempotent (calling again is a no-op).</li><li><code>resume</code> requires your <strong>passkey</strong> to install a fresh session-key validator (the session key was uninstalled, so you can&#39;t use it to re-authorize).</li></ul><p>The kill-switch is <strong>global</strong> — pausing on HavenBot pauses MCP, OpenClaw, and the hosted-checkout buyer-side tier-1 flow.</p><p>See <a href="/policy/pause">The /pause kill-switch</a>.</p><h2 id="changing-tier" tabindex="-1">Changing tier <a class="header-anchor" href="#changing-tier" aria-label="Permalink to &quot;Changing tier&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Direction</th><th>Required</th></tr></thead><tbody><tr><td>Advisory ↔ Confirm-per-action</td><td>Passkey signature (signs the new session-key validator install)</td></tr><tr><td>Confirm-per-action → Policy-bound</td><td>Passkey signature + encrypted thresholds via <code>set_policy</code> payload</td></tr><tr><td>Policy-bound → Confirm-per-action</td><td>Passkey signature (clears encrypted thresholds)</td></tr><tr><td>Any → Paused</td><td>Idempotent — no signature needed</td></tr><tr><td>Paused → Any</td><td>Passkey signature (session-key reinstall ceremony)</td></tr></tbody></table><p>The tier transition itself is recorded as a <code>tier_transition</code> audit row.</p><h2 id="why-no-fifth-tier" tabindex="-1">Why no fifth tier? <a class="header-anchor" href="#why-no-fifth-tier" aria-label="Permalink to &quot;Why no fifth tier?&quot;">​</a></h2><p>We considered:</p><ul><li><strong>&quot;Bounded auto-claim only&quot;</strong> — too narrow; Policy-bound already includes claim if you set <code>auto_claim: true</code>.</li><li><strong>&quot;Read-only&quot;</strong> — that&#39;s <code>Paused</code> plus the read tools, no additional tier needed.</li><li><strong>&quot;Per-tool tier&quot;</strong> — too complex; ladder simplicity is a feature.</li></ul><p>The four-tier ladder is the simplest model that covers the four meaningful confirmation-friction levels.</p><h2 id="where-next" tabindex="-1">Where next <a class="header-anchor" href="#where-next" aria-label="Permalink to &quot;Where next&quot;">​</a></h2><ul><li><a href="/policy/session-keys">Session keys</a> — what the session key actually authorizes.</li><li><a href="/policy/pause">The /pause kill-switch</a> — the kill-switch in depth.</li><li><a href="/policy/audit-log">Audit log</a> — what&#39;s recorded across tier transitions.</li></ul>`,49)])])}const y=t(i,[["render",n]]);export{p as __pageData,y as default};
